99	// newAgentWorkersStopCommand wires the `ddx agent workers stop` subcommand.
100	// Targeting modes are mutually exclusive:
101	//
102	//	ddx agent workers stop <worker-id>     — one worker by id
103	//	ddx agent workers stop --all-over <d>  — every running worker older than <d>
104	//	ddx agent workers stop --state <state> — every worker in <state>
105	//	ddx agent workers stop --bead <id>     — the worker assigned to <bead-id>
106	//
107	// Each match POSTs /api/agent/workers/{id}/stop on the running ddx server,
108	// which triggers the graceful SIGTERM → grace → SIGKILL path in
109	// WorkerManager.Stop. Returns a non-zero exit code if any target fails.
110	func (f *CommandFactory) newAgentWorkersStopCommand() *cobra.Command {
111		cmd := &cobra.Command{
112			Use:   "stop [worker-id]",
113			Short: "Gracefully stop running agent workers",
114			Long: `Gracefully terminate one or more running agent workers.
115	
116	The server sends SIGTERM to the worker's process group, waits for the configured
117	grace window, and escalates to SIGKILL if the leader is still alive. The worker's
118	bead claim is released and a bead.stopped event is appended to the tracker before
119	the kill, so claims are not leaked even when the full grace elapses.
120	
121	Examples:
122	  ddx agent workers stop worker-20260418T100000-abcd
123	  ddx agent workers stop --all-over 1h
124	  ddx agent workers stop --state running
125	  ddx agent workers stop --bead ddx-abc12345`,
126			RunE: f.runAgentWorkersStop,
127		}
128		cmd.Flags().Duration("all-over", 0, "Stop every running worker older than this duration")
129		cmd.Flags().String("state", "", "Stop every worker in the given state (e.g. running)")
130		cmd.Flags().String("bead", "", "Stop the worker assigned to the given bead id")
131		cmd.Flags().String("project", "", "Project root to query (default: detected from CWD)")
132		cmd.Flags().Bool("json", false, "Emit one JSON object per worker acted on")
133		return cmd
134	}
135	
136	func (f *CommandFactory) runAgentWorkersStop(cmd *cobra.Command, args []string) error {
137		allOver, _ := cmd.Flags().GetDuration("all-over")
138		stateFilter, _ := cmd.Flags().GetString("state")
139		beadFilter, _ := cmd.Flags().GetString("bead")
140		projectFlag, _ := cmd.Flags().GetString("project")
141		asJSON, _ := cmd.Flags().GetBool("json")
142	
143		// Enforce that the operator picks exactly one targeting mode.
144		modes := 0
145		if len(args) > 0 {
146			modes++
147		}
148		if allOver > 0 {
149			modes++
150		}
151		if stateFilter != "" {
152			modes++
153		}
154		if beadFilter != "" {
155			modes++
156		}
157		if modes == 0 {
158			return fmt.Errorf("specify a worker id or one of --all-over, --state, --bead")
