21		async function toggle(id: string) {
22			const next = new Set(expanded);
23			if (next.has(id)) {
24				next.delete(id);
25			} else {
26				next.add(id);
27				if (!sessionBodies[id]) {
28					const client = createClient(fetch);
29					const detail = await client.request<{ agentSession: SessionNode | null }>(
30						SESSION_DETAIL_QUERY,
31						{ id }
32					);
33					if (detail.agentSession) {
34						sessionBodies = {
35							...sessionBodies,
36							[id]: {
37								prompt: detail.agentSession.prompt,
38								response: detail.agentSession.response,
