48		const recordingGap = $derived.by(() => {
49			const sorted = [...data.sessions.edges].sort(
50				(a, b) => new Date(a.node.startedAt).getTime() - new Date(b.node.startedAt).getTime()
51			);
52			for (let i = 1; i < sorted.length; i++) {
53				const prev = new Date(sorted[i - 1].node.startedAt);
54				const next = new Date(sorted[i].node.startedAt);
55				if (next.getTime() - prev.getTime() > 24 * 60 * 60 * 1000) {
56					return `No sessions recorded between ${prev.toLocaleDateString()} and ${next.toLocaleDateString()}`;
57				}
58			}
59			return null;
60		});
