1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto } from '$app/navigation';
4		import { page } from '$app/stores';
5		import { subscribeWorkerProgress } from '$lib/gql/subscriptions';
6		import { wsConnection, type WsState } from '$lib/stores/connection.svelte';
7		import { createClient } from '$lib/gql/client';
8		import { gql } from 'graphql-request';
9		import type { WorkerRecentEvent } from './+page';
10	
11		let { data }: { data: PageData } = $props();
12	
13		let logLines = $state<string[]>([]);
14		let logContainer = $state<HTMLPreElement | null>(null);
15		let autoScroll = $state(true);
16		let liveEvents = $state<WorkerRecentEvent[]>([]);
17		let reconnecting = $state(false);
18		let catchingUp = $state(false);
19		let streamTerminal = $state(false);
20		let streamCompletedAt = $state<string | null>(null);
21		let previousWsState = $state<WsState>('idle');
22	
23		type LiveItem =
24			| { type: 'text'; text: string }
25			| { type: 'tool_call'; event: WorkerRecentEvent; key: string };
26	
27		const RECENT_EVENTS_QUERY = gql`
28			query WorkerRecentEvents($id: ID!) {
29				worker(id: $id) {
30					id
31					recentEvents {
32						kind
33						text
34						name
35						inputs
36						output
37					}
38				}
39			}
40		`;
41	
42		// Initialize log lines from initial captured stdout
43		$effect(() => {
44			const raw = data.initialLog ?? '';
45			logLines = raw.length > 0 ? raw.split('\n') : [];
46		});
47	
48		$effect(() => {
49			liveEvents = data.worker?.recentEvents ?? [];
50			streamTerminal = false;
51			streamCompletedAt = null;
52		});
53	
54		// Auto-scroll to bottom when new lines arrive (if autoScroll is enabled)
55		$effect(() => {
56			// Depend on logLines length to trigger on each new line
57			const _len = logLines.length;
58			if (autoScroll && logContainer) {
59				// Defer so DOM updates before we measure
60				Promise.resolve().then(() => {
61					if (logContainer) logContainer.scrollTop = logContainer.scrollHeight;
62				});
63			}
64		});
65	
66		// Subscribe to live worker progress events
67		$effect(() => {
68			const workerId = data.worker?.id;
69			if (!workerId || isTerminal) return;
70	
71			const dispose = subscribeWorkerProgress(workerId, (evt) => {
72				if (terminalPhases.has(evt.phase)) {
73					streamTerminal = true;
74					streamCompletedAt = evt.timestamp;
75				}
76				if (isTerminal || terminalPhases.has(evt.phase)) return;
77				if (evt.logLine != null && evt.logLine.length > 0) {
78					logLines = [...logLines, evt.logLine];
79					const frame = workerFrameFromProgressLine(evt.logLine);
80					if (frame) appendLiveEvent(frame);
81				}
82			});
83	
84			return dispose;
85		});
86	
87		$effect(() => {
88			const state = wsConnection.state;
89			reconnecting = wsConnection.showBanner || catchingUp;
90			if (
91				data.worker?.id &&
92				previousWsState !== 'idle' &&
93				previousWsState !== 'connected' &&
94				state === 'connected'
95			) {
96				void catchUpRecentEvents(data.worker.id);
97			}
98			previousWsState = state;
99		});
100	
101		function handleScroll() {
102			if (!logContainer) return;
103			const distFromBottom =
104				logContainer.scrollHeight - logContainer.scrollTop - logContainer.clientHeight;
105			autoScroll = distFromBottom < 20;
106		}
107	
108		function handleClose() {
109			const pathParts = $page.url.pathname.split('/');
110			pathParts.pop(); // remove workerId segment
111			const basePath = pathParts.join('/');
112			goto(basePath);
113		}
114	
115		function formatElapsed(ms: number): string {
116			if (ms < 1000) return `${ms}ms`;
117			if (ms < 60000) return `${(ms / 1000).toFixed(1)}s`;
118			const m = Math.floor(ms / 60000);
119			const s = Math.floor((ms % 60000) / 1000);
120			return `${m}m${s}s`;
121		}
122	
123		function inputText(input: unknown): string {
124			if (input == null) return '';
125			if (typeof input === 'string') return input;
126			return JSON.stringify(input);
127		}
128	
129		function toolLabel(event: { name: string | null; inputs: unknown }): string {
130			const details = inputText(event.inputs);
131			const summary = toolInputSummary(event.inputs);
132			if (summary && details) return `${event.name ?? 'tool'} path ${summary} ${details}`;
133			return details ? `${event.name ?? 'tool'} ${details}` : (event.name ?? 'tool');
134		}
135	
136		function toolInputSummary(input: unknown): string {
137			const parsed = typeof input === 'string' ? parseJSON(input) : input;
138			if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return '';
139			const value =
140				(parsed as Record<string, unknown>).path ?? (parsed as Record<string, unknown>).file;
141			if (typeof value !== 'string' || value.length === 0) return '';
142			return value.split('/').pop() ?? value;
143		}
144	
145		function parseJSON(value: string): unknown {
146			try {
147				return JSON.parse(value);
148			} catch {
149				return null;
150			}
151		}
152	
153		function evidenceBundleHref(workerId: string): string {
154			return `/executions/${encodeURIComponent(workerId)}/result.json`;
155		}
156	
157		function formatCompletedAt(value: string | null): string {
158			if (!value) return 'terminal state';
159			const date = new Date(value);
160			if (Number.isNaN(date.getTime())) return value;
161			return date.toLocaleTimeString([], {
162				hour: '2-digit',
163				minute: '2-digit',
164				second: '2-digit'
165			});
166		}
167	
168		function fmtDate(value: string): string {
169			const date = new Date(value);
170			if (Number.isNaN(date.getTime())) return value;
171			return date.toLocaleString();
172		}
173	
174		function fmtDuration(ms: number): string {
175			if (ms < 1000) return `${ms}ms`;
176			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`;
177			const m = Math.floor(ms / 60_000);
178			const s = Math.floor((ms % 60_000) / 1000);
179			return `${m}m ${s}s`;
180		}
181	
182		function fmtCost(cost: number | null): string {
183			return cost == null ? '—' : `$${cost.toFixed(4)}`;
184		}
185	
186		function sessionsHref(): string {
187			return `/nodes/${data.nodeId}/projects/${data.projectId}/sessions`;
188		}
189	
190		const workerSessions = $derived(data.sessions ?? []);
191		const lifecycleEvents = $derived(data.worker?.lifecycleEvents ?? []);
192	
193		function appendLiveEvent(event: WorkerRecentEvent) {
194			liveEvents = [...liveEvents, event];
195		}
196	
197		function workerFrameFromProgressLine(line: string): WorkerRecentEvent | null {
198			const trimmed = line.trim();
199			if (!trimmed.startsWith('{')) return null;
200			try {
201				const raw = JSON.parse(trimmed) as Record<string, unknown>;
202				const kind = String(raw.kind ?? raw.type ?? '');
203				const payload =
204					raw.data && typeof raw.data === 'object' ? (raw.data as Record<string, unknown>) : raw;
205				if (kind === 'text_delta') {
206					const text = raw.text ?? payload.text ?? payload.delta;
207					return typeof text === 'string'
208						? { kind: 'text_delta', text, name: null, inputs: null, output: null }
209						: null;
210				}
211				if (kind === 'tool_call') {
212					return {
213						kind: 'tool_call',
214						text: null,
215						name: typeof payload.name === 'string' ? payload.name : null,
216						inputs: inputText(payload.inputs ?? payload.input),
217						output: typeof payload.output === 'string' ? payload.output : null
218					};
219				}
220			} catch {
221				return null;
222			}
223			return null;
224		}
225	
226		async function catchUpRecentEvents(workerId: string) {
227			catchingUp = true;
228			try {
229				const client = createClient(fetch);
230				const result = await client.request<{
231					worker: { recentEvents?: WorkerRecentEvent[] } | null;
232				}>(RECENT_EVENTS_QUERY, { id: workerId });
233				liveEvents = result.worker?.recentEvents ?? liveEvents;
234			} catch (err) {
235				console.error('[ddx] worker recentEvents catch-up failed:', err);
236			} finally {
237				catchingUp = false;
238				reconnecting = wsConnection.showBanner;
239			}
240		}
241	
242		const terminalPhases = new Set(['done', 'exited', 'stopped', 'failed', 'error', 'preserved']);
243	
244		const isTerminal = $derived(
245			data.worker?.state === 'done' ||
246				data.worker?.state === 'exited' ||
247				data.worker?.state === 'stopped' ||
248				data.worker?.state === 'failed' ||
249				data.worker?.state === 'error' ||
250				streamTerminal ||
251				Boolean(data.worker?.finishedAt)
252		);
253	
254		const completedAt = $derived(data.worker?.finishedAt ?? streamCompletedAt);
255	
256		const liveItems = $derived.by(() => {
257			const items: LiveItem[] = [];
258			for (const event of liveEvents) {
259				if (event.kind === 'text_delta' && event.text) {
260					const last = items.at(-1);
261					if (last?.type === 'text') {
262						last.text += event.text;
263					} else {
264						items.push({ type: 'text', text: event.text });
265					}
266				} else if (event.kind === 'tool_call') {
267					items.push({
268						type: 'tool_call',
269						event,
270						key: `${items.length}-${event.name ?? 'tool'}-${inputText(event.inputs).slice(0, 40)}`
271					});
272				}
273			}
274			return items;
275		});
